// Accedemos directamente al nodo "Telegram Trigger" para recuperar el mensaje original
// independientemente de lo que haya pasado en los nodos intermedios
const telegramData = $("Telegram Trigger").first().json;
const message = telegramData.message;
const text = message.text || '';

// 1. Limpiar y separar por comas
const valores = text.split(',').map(v => v.trim());

// 2. Mapeo estricto por posición
const datos = {
  chat_id: message.chat.id,
  nombres:          valores[0] || '',
  apellidos:        valores[1] || '',
  nombre_comercial: valores[2] || '',
  ruc:              valores[3] || '',
  dni:              valores[4] || '',
  telefono:         valores[5] || '',
  direccion:        valores[6] || '',
  distrito:         valores[7] || '',
  estado:           'EDICION'
};

return { json: datos };

// Obtener los datos del nodo anterior (Supabase)
const data = $input.first().json;
const warnings = {};

// --- 1. VALIDACIÓN DE NOMBRES Y APELLIDOS ---
if (!data.nombres || data.nombres.trim() === '') {
  warnings.nombres = "⚠️ Falta ingresar nombres";
} else if (/\d/.test(data.nombres)) {
  warnings.nombres = "⚠️ Los nombres no deberían contener números";
}

if (!data.apellidos || data.apellidos.trim() === '') {
  warnings.apellidos = "⚠️ Falta ingresar apellidos";
} else if (/\d/.test(data.apellidos)) {
  warnings.apellidos = "⚠️ Los apellidos no deberían contener números";
}

// --- 2. VALIDACIÓN DE RUC ---
if (!data.ruc || data.ruc.trim() === '') {
  warnings.ruc = "⚠️ Falta ingresar RUC";
} else {
  const rucLimpio = data.ruc.toString().trim();
  if (!/^\d{11}$/.test(rucLimpio)) {
    warnings.ruc = "❌ El RUC debe tener 11 dígitos";
    // Check de confusión
    if (/^\d{8}$/.test(rucLimpio)) warnings.ruc = "⚠️ Esto parece un DNI, no un RUC";
  } else if (!/^(10|15|17|20)/.test(rucLimpio)) {
    warnings.ruc = "⚠️ El RUC debería empezar con 10, 20, 15 o 17";
  }
}

// --- 3. VALIDACIÓN DE DNI ---
if (!data.dni || data.dni.trim() === '') {
  warnings.dni = "⚠️ Falta ingresar DNI";
} else {
  const dniLimpio = data.dni.toString().trim();
  if (!/^\d{8}$/.test(dniLimpio)) {
    warnings.dni = "❌ El DNI debe tener 8 dígitos";
    // Check de confusión
    if (/^9\d{8}$/.test(dniLimpio)) warnings.dni = "⚠️ Esto parece un teléfono, no un DNI";
  }
}

// --- 4. VALIDACIÓN DE TELÉFONO ---
if (!data.telefono || data.telefono.trim() === '') {
  warnings.telefono = "⚠️ Falta ingresar teléfono";
} else {
  const telfLimpio = data.telefono.toString().trim();
  if (!/^9\d{8}$/.test(telfLimpio)) {
    warnings.telefono = "❌ El teléfono debe tener 9 dígitos y empezar con 9";
    // Check de confusión
    if (/^\d{8}$/.test(telfLimpio)) warnings.telefono = "⚠️ Esto parece un DNI, no un teléfono";
    if (/^\d{11}$/.test(telfLimpio)) warnings.telefono = "⚠️ Esto parece un RUC, no un teléfono";
  }
}

// --- 5. CAMPOS OPCIONALES PERO RECOMENDADOS ---
if (!data.nombre_comercial || data.nombre_comercial.trim() === '') {
  warnings.nombre_comercial = "ℹ️ Sin nombre comercial";
}
if (!data.distrito || data.distrito.trim() === '') {
  warnings.distrito = "⚠️ Falta el distrito";
}

// Retornar datos originales + objeto de warnings
return { 
  json: { 
    ...data, 
    warnings 
  } 
};

const data = $input.first().json;
const warnings = data.warnings || {};

const campos = [
  { emoji: '👤', label: 'Nom', key: 'nombres' },
  { emoji: '👥', label: 'Ape', key: 'apellidos' },
  { emoji: '🏢', label: 'Com', key: 'nombre_comercial' },
  { emoji: '🆔', label: 'RUC', key: 'ruc' },
  { emoji: '🪪', label: 'DNI', key: 'dni' },
  { emoji: '📱', label: 'Tel', key: 'telefono' },
  { emoji: '📍', label: 'Dir', key: 'direccion' },
  { emoji: '🏘️', label: 'Dis', key: 'distrito' }
];

let mensaje = "📝 *RESUMEN DE REGISTRO*\n\n";

campos.forEach((campo, index) => {
  const valor = data[campo.key] || '';
  const warning = warnings[campo.key];
  const icono = warning ? '⚠️' : '✅';

  // Formato: ✅ 1. 👤 *Nom:* `Maria`
  mensaje += `${icono} ${index + 1}. ${campo.emoji} *${campo.label}:* \`${valor || 'vacío'}\`\n`;

  // Si hay error, lo ponemos justo debajo del dato
  if (warning) {
    mensaje += `└ _${warning}_\n`;
  }
});

const tieneWarnings = Object.keys(warnings).length > 0;
mensaje += tieneWarnings 
  ? "\n⚠️ *Revisa los campos marcados.*" 
  : "\n✨ *¡Todo se ve excelente!*";

mensaje += "\n\n¿Deseas guardar los datos?";

return { 
  json: { 
    mensaje, 
    chat_id: data.chat_id,
    tiene_warnings: tieneWarnings
  } 
};

// Procesar callback queries (botones presionados)
const callback = $input.first().json.callback_query;
const chatId = callback.message.chat.id;
const callbackData = callback.data;
const messageId = callback.message.message_id;
const callbackQueryId = callback.id;

return { 
  json: { 
    chat_id: chatId, 
    callback_data: callbackData,
    message_id: messageId,
    callback_query_id: callbackQueryId
  } 
};

const callback = $node["Telegram Trigger"].json.callback_query;
