const registro = $input.first().json;
const infoCampo = $("Campo a Editar").first().json;
const campoTecnico = infoCampo.campo_tecnico;
const valorActual = registro[campoTecnico];

let mensaje = `✏️ *EDITAR: ${infoCampo.nombre_amigable}*\n\n`;

if (valorActual && valorActual.toString().trim() !== '') {
  mensaje += `Valor actual: \`${valorActual}\`\n\n`;
} else {
  mensaje += `Valor actual: _(vacío)_\n\n`;
}

mensaje += `Escribe el nuevo valor para *${infoCampo.nombre_amigable}*:`;

return {
  json: {
    chat_id: infoCampo.chat_id,
    mensaje_edicion: mensaje,
    campo_tecnico: campoTecnico,
    botones: {
      inline_keyboard: [
        [
          { text: "🗑️ Vaciar Campo", callback_data: `vaciar_${campoTecnico}` },
          { text: "🚫 Cancelar", callback_data: `cancelar_edicion` }
        ]
      ]
    }
  }
};

