const data = $input.first().json;

function escapeHtml(text) {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

const campos = [
  { emoji: '👤', label: 'Nom', key: 'nombres' },
  { emoji: '👥', label: 'Ape', key: 'apellidos' },
  { emoji: '🏢', label: 'Com', key: 'nombre_comercial' },
  { emoji: '🆔', label: 'RUC', key: 'ruc' },
  { emoji: '🪪', label: 'DNI', key: 'dni' },
  { emoji: '📱', label: 'Tel', key: 'telefono' },
  { emoji: '📍', label: 'Dir', key: 'direccion' }, // Añadido
  { emoji: '🏘️', label: 'Dis', key: 'distrito' }   // Añadido
];

let mensaje = "⏳ <b>TIENES UN REGISTRO PENDIENTE</b>\n\n";

campos.forEach(c => {
  const raw = (data[c.key] || '').toString().trim();

  if (raw) {
    const valor = escapeHtml(raw);
    mensaje += `${c.emoji} <b>${c.label}:</b> <code>${valor}</code>\n`;
  } else {
    // Si está vacío, se muestra solo la etiqueta con el emoji
    mensaje += `${c.emoji} <b>${c.label}:</b>\n`;
  }
});

mensaje += "\n⚠️ <b>¿Qué deseas hacer?</b>";
mensaje += "\n<i>(Si continúas, se ignorará la nueva lista que enviaste)</i>";

return {
  json: {
    mensaje_pendiente: mensaje,
    chat_id: data.chat_id
  }
};

